import { Link } from "react-router-dom";
import authService from "src/auth/auth.service";
import { epochTogmt } from "src/utils/Common";
import StatusDetails from "src/utils/StatusDetails";
import StatusDrop from "src/utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';

export const tableSubscriptionPlanConstant = (fetchSubscriptionPlaneList,handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "Subscription type",
            cell: (row) => {
                return (
                    <Link to={`/subcription-plan/edit/${row?.id}`}>
                        <span className="sub">{row?.subscriptionPlanType}</span>
                    </Link>
                );
            },
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 2,
            name: "Subscription amount",
            selector: (row) => row.amount
        },

        {
            id: 3,
            name: "Description",
            selector: (row) => row.description
        },
        {
            id: 4,
            name: "Create Time",
            selector: (row) => row.createdTime && epochTogmt(row.createdTime)
        },
        {
            id: 5,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row?.status} key={uuidv4()} />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 6,
            name: "Action",
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row.id}
                        status={row?.status}
                        type={'SUBSCRIPTION_PLAN'}
                        action={fetchSubscriptionPlaneList}
                        key={uuidv4()}
                        publishPermission={"SUBSCRIPTION_PLAN_PUBLISH"}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 7,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.status === "ENABLE" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row?.id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
